-- Supabase PostgreSQL DDL for project-107a8721
-- Generated from exact app data model

-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ============================================================================
-- TABLE: users
-- ============================================================================
CREATE TABLE IF NOT EXISTS public.users (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "phoneNumber" text,
  email text UNIQUE NOT NULL,
  name text,
  avatar text,
  "totalPoints" integer DEFAULT 0,
  "currentTier" text DEFAULT 'bronze',
  "createdAt" timestamp with time zone DEFAULT now(),
  "favoriteItems" text[] DEFAULT '{}',
  updated_at timestamp with time zone DEFAULT now()
);

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own profile" ON public.users
  FOR SELECT USING (auth.uid() = id);

CREATE POLICY "Users can update own profile" ON public.users
  FOR UPDATE USING (auth.uid() = id);

CREATE INDEX IF NOT EXISTS idx_users_email ON public.users(email);
CREATE INDEX IF NOT EXISTS idx_users_id ON public.users(id);

-- ============================================================================
-- TRIGGER: handle_new_user
-- Populates users table from auth.users raw_user_meta_data on signup
-- ============================================================================
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.users (id, email, "phoneNumber", name, avatar, "totalPoints", "currentTier", "favoriteItems", "createdAt", updated_at)
  VALUES (
    NEW.id,
    NEW.email,
    NEW.raw_user_meta_data ->> 'phoneNumber',
    NEW.raw_user_meta_data ->> 'name',
    NEW.raw_user_meta_data ->> 'avatar',
    COALESCE((NEW.raw_user_meta_data ->> 'totalPoints')::integer, 0),
    COALESCE(NEW.raw_user_meta_data ->> 'currentTier', 'bronze'),
    COALESCE((NEW.raw_user_meta_data -> 'favoriteItems')::text[], '{}'),
    now(),
    now()
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END; $$;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- ============================================================================
-- TABLE: transactions
-- ============================================================================
CREATE TABLE IF NOT EXISTS public.transactions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  amount numeric,
  "pointsEarned" integer,
  date timestamp with time zone,
  status text,
  "storeName" text,
  "storeAddress" text,
  "receiptNumber" text,
  created_at timestamp with time zone DEFAULT now()
);

ALTER TABLE public.transactions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own transactions" ON public.transactions
  FOR SELECT USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_transactions_userId ON public.transactions("userId");
CREATE INDEX IF NOT EXISTS idx_transactions_date ON public.transactions(date);

-- ============================================================================
-- TABLE: purchased_items
-- ============================================================================
CREATE TABLE IF NOT EXISTS public.purchased_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "transactionId" uuid NOT NULL REFERENCES public.transactions(id) ON DELETE CASCADE,
  name text,
  quantity integer,
  price numeric,
  image text,
  created_at timestamp with time zone DEFAULT now()
);

ALTER TABLE public.purchased_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view purchased items from own transactions" ON public.purchased_items
  FOR SELECT USING (
    "transactionId" IN (
      SELECT id FROM public.transactions WHERE "userId" = auth.uid()
    )
  );

CREATE INDEX IF NOT EXISTS idx_purchased_items_transactionId ON public.purchased_items("transactionId");

-- ============================================================================
-- TABLE: rewards
-- ============================================================================
CREATE TABLE IF NOT EXISTS public.rewards (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text,
  description text,
  "pointsRequired" integer,
  category text,
  image text,
  "expiresAt" timestamp with time zone,
  quantity integer,
  terms text[] DEFAULT '{}',
  created_at timestamp with time zone DEFAULT now()
);

ALTER TABLE public.rewards ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view rewards" ON public.rewards
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_rewards_category ON public.rewards(category);
CREATE INDEX IF NOT EXISTS idx_rewards_pointsRequired ON public.rewards("pointsRequired");

-- ============================================================================
-- TABLE: redemptions
-- ============================================================================
CREATE TABLE IF NOT EXISTS public.redemptions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  "rewardId" uuid NOT NULL REFERENCES public.rewards(id) ON DELETE CASCADE,
  "redeemedAt" timestamp with time zone,
  "expiresAt" timestamp with time zone,
  status text,
  "confirmationCode" text,
  created_at timestamp with time zone DEFAULT now()
