ALTER TABLE public.redemptions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own redemptions" ON public.redemptions
  FOR SELECT USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_redemptions_userId ON public.redemptions("userId");
CREATE INDEX IF NOT EXISTS idx_redemptions_rewardId ON public.redemptions("rewardId");

-- ============================================================================
